@app.route('/profile', methods=['POST'])
def update_profile():
    # 1. Authenticate the user
    current_user = authenticate_session()
    if not current_user:
        return jsonify({'message': 'Unauthorized'}), 401

    data = request.get_json()
    if not data:
        return jsonify({'message': 'Invalid JSON data'}), 400

    # 2. Extract and validate incoming data
    new_email = data.get('email')
    new_password = data.get('password') # This should be a new plain password
    twofa_enabled = data.get('2fa_enabled') # Boolean
    current_password_for_verification = data.get('current_password') # Required for sensitive changes

    # Basic validation: At least one field to update
    if not any([new_email, new_password, twofa_enabled is not None]):
        return jsonify({'message': 'No update data provided'}), 400

    # 3. Verify current password for sensitive changes
    # In a real app, you'd hash current_password_for_verification and compare it to current_user['password_hash']
    # For this example, we'll do a simplistic plain text check (DO NOT DO THIS IN PRODUCTION)
    if not current_password_for_verification:
         return jsonify({'message': 'Current password is required for profile updates'}), 403 # Forbidden
    
    # Simulate password verification (replace with actual hashing and comparison)
    if current_password_for_verification != 'plain_text_password_for_user1': # Replace with actual password verification
         return jsonify({'message': 'Incorrect current password'}), 403

    # 4. Update the profile
    updates_made = {}

    if new_email:
        # Add email format validation here
        current_user['email'] = new_email
        updates_made['email'] = new_email

    if new_password:
        # In a real app: Hash the new_password and store the hash
        current_user['password_hash'] = 'newly_hashed_password' # Replace with actual hashing
        updates_made['password_updated'] = True

    if twofa_enabled is not None:
        if isinstance(twofa_enabled, bool):
            current_user['2fa_enabled'] = twofa_enabled
            if twofa_enabled and not current_user['2fa_secret']:
                # Generate and store a new 2FA secret if enabling for the first time
                current_user['2fa_secret'] = 'new_2fa_secret_key' # Replace with actual 2FA secret generation (e.g., pyotp)
            elif not twofa_enabled:
                # Optionally clear 2FA secret if disabling
                current_user['2fa_secret'] = None
            updates_made['2fa_enabled'] = twofa_enabled
        else:
            return jsonify({'message': '2FA enabled status must be a boolean'}), 400

    if not updates_made:
        return jsonify({'message': 'No valid fields provided for update or no changes detected'}), 400

    # 5. Return success response
    return jsonify({
        'message': 'Profile updated successfully',
        'updates': updates_made
    }), 200

